"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── Context ────────────────────────────────────────────────────────────────

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

type StepperItemContextValue = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ─────────────────────────────────────────────────────────────────

function Stepper({
  orientation = "horizontal",
  activeStep,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  orientation?: "horizontal" | "vertical"
  activeStep: number
}) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal" ? "flex-row items-start" : "flex-col",
          className
        )}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

function StepperItem({
  step,
  className,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  const state: "completed" | "active" | "pending" =
    step < activeStep ? "completed" : step === activeStep ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn("flex items-center", className)}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50",
        (state === "completed" || state === "active") &&
          "bg-primary text-primary-foreground",
        state === "pending" &&
          "border border-input bg-background text-muted-foreground",
        className
      )}
      {...props}
    >
      {children ?? step}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-muted-foreground text-sm", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  const { state } = useStepperItem()

  return (
    <div
      data-slot="stepper-separator"
      data-completed={state === "completed"}
      className={cn(
        "shrink-0 rounded-full bg-border transition-colors",
        orientation === "horizontal"
          ? "h-0.5 min-w-8 flex-1"
          : "min-h-8 w-0.5 flex-1",
        state === "completed" && "bg-primary",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

function StepperContent({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & { step: number }) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      className={cn("flex-1", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
}

"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    step: 1,
    title: "Account",
    description: "Create your account",
    content:
      "Enter your email address and choose a secure password to get started.",
  },
  {
    step: 2,
    title: "Profile",
    description: "Set up your profile",
    content:
      "Add your name, profile photo, and a short bio so others can find you.",
  },
  {
    step: 3,
    title: "Complete",
    description: "You're all set!",
    content:
      "Your account is ready to go. Explore the dashboard and start building.",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(1)

  return (
    <div className="w-full max-w-sm space-y-6">
      {/*
       * Stepper wraps both the step indicators and the content panels so that
       * StepperContent can access the shared activeStep context. We override
       * the default horizontal flex to flex-col so the step row and the active
       * content panel stack vertically.
       */}
      <Stepper activeStep={activeStep} className="w-full flex-col gap-6">
        {/* ── Step indicators row ── */}
        <div className="flex w-full">
          {steps.map(({ step, title, description }, index) => (
            <StepperItem
              key={step}
              step={step}
              className={index < steps.length - 1 ? "flex-1 flex-col gap-1.5" : "flex-col gap-1.5"}
            >
              <div className="flex w-full items-center gap-2">
                <StepperTrigger onClick={() => setActiveStep(step)} />
                {index < steps.length - 1 && <StepperSeparator />}
              </div>
              <StepperTitle>{title}</StepperTitle>
              <StepperDescription>{description}</StepperDescription>
            </StepperItem>
          ))}
        </div>

        {/* ── Content panels (only the active one renders) ── */}
        {steps.map(({ step, title, content }) => (
          <StepperContent key={step} step={step}>
            <div className="rounded-lg border p-4">
              <p className="text-sm font-medium">{title}</p>
              <p className="text-muted-foreground mt-1 text-sm">{content}</p>
            </div>
          </StepperContent>
        ))}
      </Stepper>

      {/* ── Navigation ── */}
      <div className="flex gap-2">
        <Button
          variant="outline"
          size="sm"
          onClick={() => setActiveStep((s) => Math.max(1, s - 1))}
          disabled={activeStep === 1}
        >
          Previous
        </Button>
        <Button
          size="sm"
          onClick={() => setActiveStep((s) => Math.min(steps.length, s + 1))}
          disabled={activeStep === steps.length}
        >
          Next
        </Button>
      </div>
    </div>
  )
}

},
